import React, {useState, useRef, useEffect} from 'react'
import styled from 'styled-components'
import {getDesigner} from '../WebAPI'


const DropDownWrapper = styled.div `
padding:20px 40px;
width:90%;
height:300px;
top:140px;
bottom:0;
left:0;
right:0;
margin:0 auto;
border-radius:0 0 3px 3px;
border:1px solid white;
display:flex;
align-items:center;
justidy-content:space-between;
position:absolute;
color:#1C1C1C;
background-color:white;
z-index:3;
`

const Title = styled.div `
font-size:1.3rem;
font-weight:200;
`

const Designer = styled.div `
width:20%;
font-size:1rem;
margin:6px 0;
display:inline-block;
`

const DesignerWrapper = styled.div `
display:flex;
flex-direction:column;
height:300px;
width:1000px;
margin:0 auto;
flex-wrap:wrap;
` 

export default function DesignerDropdown() {
	const [designer, setDesigner] = useState([{}])

	useEffect(() => {
		getDesigner(setDesigner)
	},[])



	return (
		<DropDownWrapper>
			<Title>Designers A-Z</Title>
			<DesignerWrapper>
				{designer.map(designer => <Designer key={`${designer.id}:${designer.index}`}>{designer.name}</Designer>)}
			</DesignerWrapper>
		</DropDownWrapper>
	)
}
